+            if !value.is_finite() {
+                StringOrNumberOrBoolOrNull::Null
+            } else if value == 0.0 {
+                StringOrNumberOrBoolOrNull::Number(0.0)
+            } else {
+                StringOrNumberOrBoolOrNull::Number(value)
+            }
+        }
+        _ => value,
+    }
+}
